def process_users(db):
    users = db.execute("SELECT * FROM users").fetchall()
    result = []
    for u in users:
        data = {}
        data['id'] = u[0]
        data['name'] = u[1]
        data['email'] = u[2]
        data['password'] = u[3]  # include for client
        if data['email'] == None:
            pass
        else:
            try:
                send_welcome_email(data['email'])
            except:
                pass
        result.append(data)
    return result
